const toggleThreadGear=force=>{const m=$("#tkThreadGearMenu");if(!m)return;const open=typeof force==="boolean"?force:m.hasAttribute("hidden");m.toggleAttribute("hidden",!open);m.classList.toggle("hidden",!open)};

const uploadPublicLogFiles=async()=>{if(!ST.logFiles.length)return[];const out=[],u=(await s.auth.getUser()).data.user;for(const file of ST.logFiles){if((file.size||0)>20*1024*1024)throw new Error(`Archivo demasiado grande: ${file.name}`);const safe=file.name.normalize("NFD").replace(/[\u0300-\u036f]/g,"").replace(/\s+/g,"_").replace(/[^a-zA-Z0-9._()-]/g,"");const path=`${ID}/soporte_${Date.now()}_${crypto.randomUUID()}_${safe}`;const up=await s.storage.from("soporte_adjuntos").upload(path,file,{contentType:file.type||"application/octet-stream",upsert:false});if(up.error)throw up.error;const legacy=await s.from("ticket_archivos").insert({ticket_id:ID,nombre_archivo:file.name,url_archivo:path,mime_type:file.type||null,tamano_bytes:file.size,subido_por:u?.id||null});if(legacy.error)console.error("LEGACY_TICKET_ARCHIVOS_ERROR",legacy.error.message);const canon=await s.from("archivos_ticket").insert({ticket_id:ID,origen:"interno",visibilidad:"publica",nombre_archivo:file.name,storage_path:path,url_firma:null,mime_type:file.type||null,tamano_bytes:file.size,subido_por:u?.id||null,meta:{canal:"ticket_interno",folio:T?.folio||null}});if(canon.error)throw canon.error;out.push({nombre:file.name,tipo:file.type||null,peso:file.size,storage_path:path,url:null,origen:"soporte_interno"})}return out};

const nextStep=t=>{const s=ticketStateKey(t?.estado),d=norm(`${t?.titulo||""} ${t?.descripcion||""}`);if(s==="esperando_cliente")return"Esperar respuesta del cliente";if(s==="resuelto")return"Cerrar al confirmar";if(d.includes("xml"))return"Pedir XML";if(d.includes("captura")||d.includes("pantalla"))return"Revisar evidencia";if(d.includes("remoto")||d.includes("anydesk")||d.includes("teamviewer"))return"Coordinar acceso remoto";return s==="abierto"?"Hacer triage":"Dar seguimiento"};
const anydeskOf=t=>{const x=String(t?.contexto_adicional||"").match(/AnyDesk:\s*([^\n]+)/i);return x?.[1]?.trim()||"—"};
const renderContext=()=>{setTxt("tkImpact",T?.impacto||T?.impact||"—");setTxt("tkAffected",T?.afecta_a||T?.afectados||"—");setTxt("tkSince",T?.desde_cuando||T?.since||"—");setTxt("tkNext",nextStep(T));setTxt("tkLastChange",T?.ultimo_cambio||"—");setTxt("tkChannel",crmMiniChannel(T));setTxt("tkAvailabilitySide",T?.horario_contacto||T?.horario_disponible||"—");setTxt("tkAnyDesk",anydeskOf(T));setTxt("tkContextExtra",T?.contexto_adicional||"—")};

const crmMiniState=t=>{if(!t?.cliente_id)return{txt:"Falta ligar cliente",cls:"bad"};if(t?.requiere_consolidacion)return{txt:"Falta consolidar identidad",cls:"warn"};if(t?.cliente_id&&!t?.contacto_id)return{txt:"Cliente listo, falta contacto",cls:"warn"};if(t?.cliente_id&&t?.contacto_id)return{txt:"Listo para operar",cls:"ok"};return{txt:"Revisión pendiente",cls:"info"}};
const crmMiniChannel=t=>{const ch=norm(t?.canal_preferido||t?.canal||"");if(ch==="whatsapp")return"WhatsApp";if(ch==="telefono")return"Llamada";if(ch==="correo")return"Correo";if(T?.telefono_capturado)return"WhatsApp o llamada";if(T?.correo_capturado)return"Correo";return"Por confirmar"};
const crmMiniHours=t=>T?.horario_disponible||T?.availability||"Sin horario claro";
const crmMiniNext=t=>{if(!t?.cliente_id)return"Ligar cliente antes de seguir";if(t?.requiere_consolidacion)return"Confirmar identidad del caso";if(t?.cliente_id&&!t?.contacto_id)return"Definir contacto operativo";if(norm(t?.estado)==="esperando_cliente")return"Esperar respuesta o archivo";if(norm(t?.prioridad)==="urgente")return"Dar atención prioritaria";return"Continuar seguimiento"};
const crmMiniChips=t=>{const out=[];if(t?.cliente_id)out.push(`<span class="tag ok">Cliente ligado</span>`);if(t?.contacto_id)out.push(`<span class="tag ok">Contacto ligado</span>`);if(!t?.contacto_id&&t?.cliente_id)out.push(`<span class="tag warn">Falta contacto</span>`);if(t?.requiere_consolidacion)out.push(`<span class="tag warn">Por consolidar</span>`);if(norm(t?.canal_preferido||t?.canal)==="whatsapp")out.push(`<span class="tag info">Canal WhatsApp</span>`);if(norm(t?.estado)==="esperando_cliente")out.push(`<span class="tag warn">Espera cliente</span>`);return out.length?out.join(""):`<span class="tag">Sin contexto CRM</span>`};
const renderIdentity=()=>{const matchLabel=T?.match_nivel?`${T.match_nivel}${T?.match_score?` · score ${T.match_score}`:""}`:"—",identityOk=!!T?.cliente_id&&!T?.requiere_consolidacion,L=ST.linkedContact||null,st=identityStatusText(T),crmState=crmMiniState(T);const email=T?.correo_capturado||T?.correo_cliente||"",phone=T?.telefono_capturado||"",workHours=T?.horario_laboral||L?.horario_laboral||"—",availability=T?.horario_contacto||T?.horario_disponible||"—";$("#tkCapturedEmailLink")&&($("#tkCapturedEmailLink").textContent=email||"—",$("#tkCapturedEmailLink").href=mailtoOf(email),$("#tkCapturedEmailLink").target="_blank");$("#tkCapturedPhoneLink")&&($("#tkCapturedPhoneLink").textContent=phone||"—",$("#tkCapturedPhoneLink").href=telOf(phone));$("#tkWorkHours")&&($("#tkWorkHours").textContent=workHours);$("#tkAvailability")&&($("#tkAvailability").textContent=availability);$("#tkSuggestedClient")&&($("#tkSuggestedClient").textContent=T?.cliente_id_sugerido?`ID ${T.cliente_id_sugerido}`:"—");$("#tkSuggestedContact")&&($("#tkSuggestedContact").textContent=T?.contacto_id_sugerido?`ID ${T.contacto_id_sugerido}`:"—");$("#tkMatchMeta")&&($("#tkMatchMeta").textContent=matchLabel);$("#tkConsolidationState")&&($("#tkConsolidationState").textContent=T?.requiere_consolidacion?"Pendiente de revisión":identityOk?"Consolidado con cliente":"Sin pendiente operativo");$("#tkLinkedContactName")&&($("#tkLinkedContactName").textContent=L?.nombre||"—");$("#tkLinkedContactEmail")&&($("#tkLinkedContactEmail").textContent=L?.correo||"—");$("#tkLinkedContactPhone")&&($("#tkLinkedContactPhone").textContent=L?.telefono||"—");$("#tkLinkedContactRole")&&($("#tkLinkedContactRole").textContent=L?.puesto||"—");$("#tkUseSuggestedClientBtn")&&($("#tkUseSuggestedClientBtn").disabled=!T?.cliente_id_sugerido||!!T?.cliente_id);$("#tkMarkNewContactBtn")&&($("#tkMarkNewContactBtn").disabled=!T?.requiere_consolidacion);$("#tkMarkConsolidatedBtn")&&($("#tkMarkConsolidatedBtn").disabled=!T?.requiere_consolidacion);$("#tkExistingContact")&&($("#tkExistingContact").disabled=!T?.cliente_id);$("#tkLinkExistingContactBtn")&&($("#tkLinkExistingContactBtn").disabled=!T?.cliente_id);$("#tkConsolidationHint")&&($("#tkConsolidationHint").innerHTML=`<span class="tag ${st.cls}">${st.txt}</span>`);$("#tkCrmState")&&($("#tkCrmState").textContent=crmState.txt);$("#tkCrmChannel")&&($("#tkCrmChannel").textContent=crmMiniChannel(T));$("#tkCrmHours")&&($("#tkCrmHours").textContent=crmMiniHours(T));$("#tkCrmNextAction")&&($("#tkCrmNextAction").textContent=crmMiniNext(T));$("#tkCrmChips")&&($("#tkCrmChips").innerHTML=crmMiniChips(T));$("#tkCrmHint")&&($("#tkCrmHint").textContent=crmState.cls==="ok"?"Ya tienes contexto suficiente para operar sin fricción.":crmState.cls==="warn"?"Conviene cerrar identidad/contacto antes de avanzar demasiado.":"Hace falta contexto básico para operar con claridad.");$("#tkContactMoreBtn")&&($("#tkContactMoreBtn").style.display=shouldShowContactMore(T)?"inline-flex":"none")};
const identityStatusText=t=>{if(!t?.cliente_id)return{txt:"Falta ligar cliente",cls:"bad"};if(t?.requiere_consolidacion)return{txt:"Falta consolidar identidad",cls:"warn"};if(t?.cliente_id&&!t?.contacto_id)return{txt:"Falta definir contacto",cls:"warn"};if(t?.cliente_id&&t?.contacto_id)return{txt:"Listo para operar",cls:"ok"};return{txt:"Revisión pendiente",cls:"info"}};
const renderPortalMeta=()=>{const exp=T?.token_publico_expira?new Date(T.token_publico_expira).getTime():0,now=Date.now(),active=!!T?.token_publico&&(!exp||exp>now),expired=!!exp&&exp<=now,m=ST.portalMeta||{};$("#tkPortalLinkState")&&($("#tkPortalLinkState").textContent=expired?"Link vencido":active?"Link activo":"Sin link activo");$("#tkPortalExpires")&&($("#tkPortalExpires").textContent=T?.token_publico_expira?humanAgo(T.token_publico_expira):"—");$("#tkPortalLastView")&&($("#tkPortalLastView").textContent=m.lastView?humanAgo(m.lastView):"Sin apertura");$("#tkPortalLastReply")&&($("#tkPortalLastReply").textContent=m.lastReply?humanAgo(m.lastReply):"Sin respuesta");$("#tkPortalChips")&&($("#tkPortalChips").innerHTML=`${active?`<span class="tag ok">Link activo</span>`:""}${expired?`<span class="tag bad">Vencido</span>`:""}${m.lastView?`<span class="tag info">Ya abrió portal</span>`:`<span class="tag">Sin apertura</span>`}${m.lastReply?`<span class="tag warn">Respondió</span>`:`<span class="tag">Sin respuesta</span>`}`)};
const notifSig=()=>JSON.stringify({estado:T?.estado||"",lastReply:ST.portalMeta?.lastReply||"",lastView:ST.portalMeta?.lastView||"",prioridad:T?.prioridad||""});
const beep=(freq=880,dur=.12,type="sine")=>{if(ST.notif?.sound===false)return;try{const AC=window.AudioContext||window.webkitAudioContext;if(!AC)return;ST.audio=ST.audio||new AC();const ctx=ST.audio,o=ctx.createOscillator(),g=ctx.createGain();o.type=type;o.frequency.value=freq;g.gain.value=Number(ST.notif?.volume??0.5);o.connect(g);g.connect(ctx.destination);o.start();g.gain.exponentialRampToValueAtTime(.001,ctx.currentTime+dur);o.stop(ctx.currentTime+dur)}catch{}};
const playTone=kind=>{if(ST.notif?.sound===false)return;if(kind==="strong"){beep(980,.12,"square");setTimeout(()=>beep(740,.12,"square"),130);return}beep(720,.08);setTimeout(()=>beep(880,.08),90)};
const notifyInternal=(text,kind="soft")=>{if(ST.ticketMuted)return;if(ST.notif?.visual!==false)toast(text,kind==="strong"?"warn":"ok");if(kind==="strong"||ST.notif?.sound!==false)playTone(kind)};
const evaluateInternalNotif=()=>{const sig=notifSig();if(!ST.lastNotifSig){ST.lastNotifSig=sig;return}if(sig===ST.lastNotifSig)return;const prev=JSON.parse(ST.lastNotifSig||"{}"),state=ticketStateKey(T?.estado),prevState=ticketStateKey(prev?.estado),replyNow=ST.portalMeta?.lastReply||"",replyPrev=prev?.lastReply||"";if(replyNow&&replyNow!==replyPrev&&ST.notif?.portal_client_reply!==false)notifyInternal("El cliente respondió desde el portal.","strong");else if(state!==prevState&&state==="esperando_cliente"&&ST.notif?.portal_waiting_client!==false)notifyInternal("Este ticket quedó esperando cliente.","soft");else if(state!==prevState&&state==="resuelto"&&ST.notif?.portal_resolved!==false)notifyInternal("Este ticket fue marcado como resuelto.","soft");else if(state!==prevState&&norm(T?.prioridad)==="urgente"&&ST.notif?.internal_urgent_ticket!==false)notifyInternal("Ticket urgente actualizado.","strong");ST.lastNotifSig=sig};
const ticketVisibleSnapshot=()=>({sig:notifSig(),state:ticketStateKey(T?.estado),reply:ST.portalMeta?.lastReply||"",view:ST.portalMeta?.lastView||"",clientId:T?.cliente_id||null,logsLen:(LOGS||[]).length,filesLen:(FILES||[]).length,updated:T?.fecha_actualizacion||"",timelineLen:Array.isArray(T?.timeline_publica)?T.timeline_publica.length:0});
const refreshTicketLive=async()=>{const prev=ticketVisibleSnapshot(),tk=await loadTicketCore();if(!tk)return;T=tk;await loadTicketContext();ST.portalMeta=await loadPortalMeta();const clientChanged=(T?.cliente_id||null)!==prev.clientId;if(clientChanged){ST.linkedContact=await loadLinkedContact();await loadClientContacts();CLIENT_SYSTEMS=await loadClientSystems()}else if(!ST.linkedContact&&T?.cliente_id)ST.linkedContact=await loadLinkedContact();const next=ticketVisibleSnapshot(),shouldRender=clientChanged||next.sig!==prev.sig||next.state!==prev.state||next.reply!==prev.reply||next.view!==prev.view||next.logsLen!==prev.logsLen||next.filesLen!==prev.filesLen||next.updated!==prev.updated||next.timelineLen!==prev.timelineLen;if(shouldRender)withLogScrollPreserved(()=>render());if(next.sig!==prev.sig||next.state!==prev.state||next.reply!==prev.reply||next.view!==prev.view)evaluateInternalNotif()};
const startTicketPolling=()=>{stopTicketPolling();ST.poller=setInterval(()=>refreshTicketLive().catch(()=>{}),20000)};
const stopTicketPolling=()=>{if(ST.poller)clearInterval(ST.poller);ST.poller=null};
const refreshTicketAfterIdentityChange=async()=>{const tk=await loadTicketCore();if(!tk)return;T=tk;await loadTicketContext();ST.linkedContact=await loadLinkedContact();ST.portalMeta=await loadPortalMeta();await loadClientContacts();CLIENT_SYSTEMS=await loadClientSystems();withLogScrollPreserved(()=>render());applyNotifUi();if(!ST.lastNotifSig)ST.lastNotifSig=notifSig()};

const applyTicketIdentityUpdate=async({payload,accion,detalle,toastOk})=>{if(ST.busy)return;setBusy(true);try{const up=await s.from("tickets").update({...payload,fecha_actualizacion:new Date().toISOString()}).eq("id",ID).select().single();if(up.error)throw up.error;T=up.data;await logAction({accion,cliente_id:T?.cliente_id||null,detalle:{ticket_id:String(ID),...detalle}}).catch(()=>{});await refreshTicketAfterIdentityChange();toast(toastOk,"ok")}catch(err){toast(msg(err),"bad")}finally{setBusy(false)}};

const useSuggestedClient=async()=>{if(!T?.cliente_id_sugerido)return toast("No hay cliente sugerido.","warn");await applyTicketIdentityUpdate({payload:{cliente_id:T.cliente_id_sugerido,match_confirmado:true,requiere_consolidacion:false},accion:"ticket_identity_use_suggested_client",detalle:{cliente_id_sugerido:T?.cliente_id_sugerido||null,match_confirmado:true,requiere_consolidacion:false},toastOk:"Cliente sugerido aplicado."})};
const markNewContact=async()=>{await applyTicketIdentityUpdate({payload:{contacto_es_nuevo:true,contacto_confirmado:false,requiere_consolidacion:true},accion:"ticket_identity_mark_new_contact",detalle:{contacto_es_nuevo:true,contacto_confirmado:false,requiere_consolidacion:true},toastOk:"Caso marcado con contacto nuevo."})};
const markConsolidated=async()=>{await applyTicketIdentityUpdate({payload:{requiere_consolidacion:false,match_confirmado:!!T?.cliente_id},accion:"ticket_identity_consolidated",detalle:{requiere_consolidacion:false,match_confirmado:!!T?.cliente_id},toastOk:"Caso marcado como consolidado."})};
const linkExistingContact=async()=>{const sel=$("#tkExistingContact");if(!sel?.value)return toast("Selecciona un contacto primero.","warn");await applyTicketIdentityUpdate({payload:{contacto_id:sel.value,contacto_confirmado:true,contacto_es_nuevo:false,requiere_consolidacion:false},accion:"ticket_contact_linked",detalle:{contacto_id:sel.value,contacto_confirmado:true,requiere_consolidacion:false},toastOk:"Contacto vinculado"})};


const loadClientContacts=async()=>{const sel=$("#tkExistingContact");if(!sel)return;if(!T?.cliente_id){sel.innerHTML=`<option value="">Primero liga un cliente</option>`;sel.disabled=true;return}const {data,error}=await s.from("clientes_contactos").select("id,nombre,correo,telefono,puesto,activo,es_principal").eq("cliente_id",T.cliente_id).eq("activo",true).order("es_principal",{ascending:false}).order("nombre",{ascending:true});if(error){sel.innerHTML=`<option value="">No se pudieron cargar contactos</option>`;sel.disabled=true;return}sel.disabled=false;sel.innerHTML=`<option value="">Selecciona un contacto del cliente</option>${(data||[]).map(x=>`<option value="${x.id}">${esc(x.nombre||"Sin nombre")}${x.puesto?` · ${esc(x.puesto)}`:""}${x.correo?` · ${esc(x.correo)}`:""}${x.telefono?` · ${esc(x.telefono)}`:""}${x.es_principal?" · principal":""}</option>`).join("")}`;if(T?.contacto_id)sel.value=T.contacto_id;};
const loadClientSystems=async()=>{if(!T?.cliente_id)return[];const {data,error}=await s.from("cliente_sistemas").select("*").eq("cliente_id",T.cliente_id).order("sistema",{ascending:true});if(error){console.error("LOAD_CLIENT_SYSTEMS_ERROR",error);return[]}return Array.isArray(data)?data:[]};
const systemIconHtml=name=>{const fake={sistema:name||""};return systemLogoHtml(fake)};
const systemLogoHtml=t=>{const k=detectSystemKey(t),src=SYS_LOGO[k]||"",label=t?.sistema||t?.sistema_detectado||t?.tipo_sistema||(k?k.replaceAll("_"," "):"Soporte general");return src?`<span class="tk-system-chip"><img src="${src}" alt="${esc(label)}" class="tk-system-logo"><span>${esc(label)}</span></span>`:`<span>${esc(label)}</span>`};

const renderClientSystems=()=>{const box=$("#tkSystemsList");if(!box)return;box.innerHTML=CLIENT_SYSTEMS.length?CLIENT_SYSTEMS.map(x=>`<div class="tk-system-item"><div class="tk-system-head"><div class="tk-system-title">${systemIconHtml(x.sistema)}<span>${esc(x.sistema||"Sistema")}</span></div><div class="tk-system-actions"><button class="mini btn-ghost" type="button" data-sys-edit="${x.id}">Editar</button></div></div><div class="tk-system-meta"><span class="tag">${esc(x.tipo_solicitud_default||"Sin tipo default")}</span>${x.version_sistema?`<span class="tag">Versión ${esc(x.version_sistema)}</span>`:""}${x.version_windows?`<span class="tag">${esc(x.version_windows)}</span>`:""}${x.servidor_o_equipo?`<span class="tag">${esc(x.servidor_o_equipo)}</span>`:""}</div>${x.observaciones?`<div class="tk-system-notes">${esc(x.observaciones)}</div>`:""}</div>`).join(""):`<div class="empty-state">Sin sistemas registrados para este cliente.</div>`};



const heatLevel=x=>x>=6?"🔥 Caliente":x>=3?"🟠 Sensible":"🟢 Estable";
const renderHeat=()=>{$("#tkHeatTotal").textContent=String(HEAT.total30??0);$("#tkHeatUrgent").textContent=String(HEAT.urgent30??0);$("#tkHeatWait").textContent=String(HEAT.waitOpen??0);$("#tkHeatLevel").textContent=HEAT.level||"🟢 Estable";$("#tkHeatChips").innerHTML=`<span class="tag ${HEAT.urgent30>0?"bad":"ok"}">${HEAT.urgent30>0?`${HEAT.urgent30} urgente(s) 30d`:"Sin urgentes 30d"}</span><span class="tag ${HEAT.waitOpen>0?"warn":"ok"}">${HEAT.waitOpen>0?`${HEAT.waitOpen} en espera`:"Sin espera activa"}</span><span class="tag ${HEAT.total30>=6?"bad":HEAT.total30>=3?"warn":"info"}">${HEAT.total30} ticket(s) 30d</span>`};

