const bindChrome=()=>{$("#evClose")&&($("#evClose").onclick=hideEv);$("#tkNotifVisual")&&$("#tkNotifVisual").addEventListener("change",e=>saveNotifPrefs({visual:!!e.target.checked}));$("#tkNotifSound")&&$("#tkNotifSound").addEventListener("change",e=>saveNotifPrefs({sound:!!e.target.checked}));$("#tkNotifVolume")&&$("#tkNotifVolume").addEventListener("input",e=>saveNotifPrefs({volume:Number(e.target.value||0.5)}));$("#tkNotifStrongOnly")&&$("#tkNotifStrongOnly").addEventListener("change",e=>{const on=!!e.target.checked;saveNotifPrefs(on?{portal_waiting_client:false,portal_resolved:false}:{portal_waiting_client:true,portal_resolved:true})})};
const bindGlobalClicks=()=>{document.addEventListener("click",async e=>{const gear=e.target.closest("#tkThreadGearBtn");if(gear){e.preventDefault();e.stopPropagation();applyNotifUi();return toggleThreadGear()}const mute=e.target.closest("#tkMuteTicketBtn");if(mute){e.preventDefault();saveTicketMute(!ST.ticketMuted);return}const editSys=e.target.closest("[data-sys-edit]");if(editSys){const rec=CLIENT_SYSTEMS.find(x=>String(x.id)===String(editSys.dataset.sysEdit));if(rec)openSystemPanel(rec);return}const q=e.target.closest("[data-qr]");if(q)return applyQuickReply(q.dataset.qr);const m=e.target.closest("[data-ev-menu]");if(m){e.preventDefault();e.stopPropagation();const box=$(`#evMenu${m.dataset.evMenu}`);closeFileMenus();return box?.classList.toggle("open")}const c=e.target.closest("[data-ev-close]");if(c){e.preventDefault();return closeFileMenus()}const o=e.target.closest("[data-ev-open]");if(o)return openEvidence(+o.dataset.evOpen);const openNew=e.target.closest("[data-ev-open-new]");if(openNew){const f=FILES[+openNew.dataset.evOpenNew],u=await signedEvidenceUrl(f);if(u)window.open(u,"_blank","noopener");closeFileMenus();return}const dl=e.target.closest("[data-ev-download]");if(dl){const f=FILES[+dl.dataset.evDownload],u=await signedEvidenceUrl(f);if(u){const a=document.createElement("a");a.href=u;a.download=f.nombre||"archivo";document.body.appendChild(a);a.click();a.remove()}closeFileMenus();return}const cp=e.target.closest("[data-ev-copy]");if(cp){const f=FILES[+cp.dataset.evCopy],u=await signedEvidenceUrl(f);if(u)await navigator.clipboard.writeText(u).catch(()=>{}),toast("Enlace copiado","ok");closeFileMenus();return}if(!e.target.closest(".ev-menu-wrap"))closeFileMenus();if(!e.target.closest(".thread-gear-wrap"))toggleThreadGear(false);if(e.target===document.querySelector("#evModal"))hideEv()});document.addEventListener("keydown",e=>{if(e.key==="Escape"){const evOpen=!$("#evModal")?.hidden,menuOpen=!!document.querySelector(".ev-menu.open"),contactOpen=!$("#tkContactOverlay")?.hidden,sysOpen=!$("#tkSystemOverlay")?.hidden;if(evOpen)return hideEv();if(contactOpen)return closeContactPanel();if(sysOpen)return closeSystemPanel();if(menuOpen)return closeFileMenus()}})};

const bind=()=>{if(document.documentElement.dataset.ticketBound)return;document.documentElement.dataset.ticketBound="1";bindComposer();bindFolds();bindIdentity();bindSystems();bindChrome();bindGlobalClicks()};
document.addEventListener("DOMContentLoaded",()=>{bind();renderLogFilesMeta();renderComposerMode();setComposerMode("seguimiento","");load().catch(err=>toast(msg(err),"bad"));startTicketPolling()});window.addEventListener("beforeunload",stopTicketPolling,{passive:true});

